    ('SPH-V 692', 'RESEARCH IN ENVIRONMENTAL HEALTH', '14157', 'Class Status', NULL, NULL, 'Justin Greaves', 2, NULL, 'Research', '1–3', NULL, ARRAY[]::TEXT[], 'Research projects are conducted under the direction of a member of the Environmental Health Graduate teaching faculty. Enrollment is limited to Advanced Graduate Students upon the approval of Faculty.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 692', 'RESEARCH IN ENVIRONMENTAL HEALTH', '14162', 'Class Status', NULL, NULL, 'Eduardo Ximenes', 2, NULL, 'Research', '1–3', NULL, ARRAY[]::TEXT[], 'Research projects are conducted under the direction of a member of the Environmental Health Graduate teaching faculty. Enrollment is limited to Advanced Graduate Students upon the approval of Faculty.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 692', 'RESEARCH IN ENVIRONMENTAL HEALTH', '14152', 'Closed', NULL, NULL, 'Drew Capone', 0, NULL, 'Research', '1–3', NULL, ARRAY[]::TEXT[], 'Research projects are conducted under the direction of a member of the Environmental Health Graduate teaching faculty. Enrollment is limited to Advanced Graduate Students upon the approval of Faculty.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 733', 'RESEARCH METHODS IN ENVIRONMENTAL HEALTH', '11370', 'Class Status', 'MW Monday, Wednesday 3:30 PM–4:45 PM', 'HD TBA', 'Patricia Silveyra', 25, NULL, 'Methods Course', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This course is required for doctoral students in Environmental and Occupational Health. Students will be introduced to methodological concepts and techniques, and use problem-based, practical approaches to research in environmental health. Emphasis will be placed on research question conceptualization, study design, hypothesis-testing, data analysis and interpretation, and results presentation.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 743', 'ENVIRONMENTAL HEALTH SAMPLING', '14148', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HD TBA', 'Drew Capone', 8, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This course introduces students to the basic principles of environmental sampling and analysis to prevent or reduce public health hazards. Lectures and labs will examine sampling and analytical methods used to measure contaminants in the workplace and in community environments.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 791', 'ADVANCED ENVIRONMENTAL HEALTH READINGS', '14299', 'Class Status', NULL, NULL, 'Funmilola Ayeni', 2, NULL, 'Readings', '1–3', NULL, ARRAY[]::TEXT[], 'The main goal of this variable credit hour class is to help doctoral degree students develop some of the readings skills required for successfully completing the dissertation.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 791', 'ADVANCED ENVIRONMENTAL HEALTH READINGS', '14309', 'Class Status', NULL, NULL, 'Roberto Rodriguez', 2, NULL, 'Readings', '1–3', NULL, ARRAY[]::TEXT[], 'The main goal of this variable credit hour class is to help doctoral degree students develop some of the readings skills required for successfully completing the dissertation.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 792', 'ADVANCED ENVIRONMENTAL HEALTH RESEARCH', '14273', 'Class Status', NULL, NULL, 'Justin Greaves', 2, NULL, 'Research', '1–3', NULL, ARRAY[]::TEXT[], 'The main goal of this variable credit hour class is to help doctoral degree students develop some of the research skills required for successfully completing the dissertation.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 792', 'ADVANCED ENVIRONMENTAL HEALTH RESEARCH', '14278', 'Class Status', NULL, NULL, 'Kan Shao', 2, NULL, 'Research', '1–3', NULL, ARRAY[]::TEXT[], 'The main goal of this variable credit hour class is to help doctoral degree students develop some of the research skills required for successfully completing the dissertation.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 799', 'PHD DISSERTATION IN ENVIRONMENTAL HEALTH', '12840', 'Class Status', NULL, NULL, 'Patricia Silveyra', 4, NULL, 'Research', '1–30', NULL, ARRAY[]::TEXT[], 'Every dissertation presented in partial fulfillment of the requirements for an advanced degree must represent the equivalent of at least 30 semester hours of work.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 799', 'PHD DISSERTATION IN ENVIRONMENTAL HEALTH', '14321', 'Class Status', NULL, NULL, 'Drew Capone', 2, NULL, 'Research', '1–30', NULL, ARRAY[]::TEXT[], 'Every dissertation presented in partial fulfillment of the requirements for an advanced degree must represent the equivalent of at least 30 semester hours of work.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 799', 'PHD DISSERTATION IN ENVIRONMENTAL HEALTH', '14323', 'Class Status', NULL, NULL, 'Sarah Commodore', 2, NULL, 'Research', '1–30', NULL, ARRAY[]::TEXT[], 'Every dissertation presented in partial fulfillment of the requirements for an advanced degree must represent the equivalent of at least 30 semester hours of work.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 799', 'PHD DISSERTATION IN ENVIRONMENTAL HEALTH', '14324', 'Class Status', NULL, NULL, 'Michelle Del Rio', 1, NULL, 'Research', '1–30', NULL, ARRAY[]::TEXT[], 'Every dissertation presented in partial fulfillment of the requirements for an advanced degree must represent the equivalent of at least 30 semester hours of work.', ARRAY[]::TEXT[], NULL),
    ('SPH-W 113', 'BACKPACKING', '8829', 'Class Status', 'M Monday 6:40 PM–9:10 PM', 'EG 020', 'Hannah McConnell, Niccole Brown', 1, NULL, 'Activity', '2', 'EIGENMANN HALL', ARRAY[]::TEXT[], 'Designed to introduce the basics of backpacking and backcountry camping, proper equipment selection, topographic map use, water purification, campsite selection, and Leave No Trace ethics. A highly experience-based course where students will engage in a weekend field experience involving group dynamics, genuine reflection, and new skill demonstration. More information: outdoors.iu.edu/academics', ARRAY[]::TEXT[], NULL),
    ('SPH-W 113', 'BACKPACKING', '8830', 'Class Status', 'Tu Tuesday 6:40 PM–9:10 PM', 'EG 020', 'Hannah McConnell, Niccole Brown', 2, NULL, 'Activity', '2', 'EIGENMANN HALL', ARRAY[]::TEXT[], 'Designed to introduce the basics of backpacking and backcountry camping, proper equipment selection, topographic map use, water purification, campsite selection, and Leave No Trace ethics. A highly experience-based course where students will engage in a weekend field experience involving group dynamics, genuine reflection, and new skill demonstration. More information: outdoors.iu.edu/academics', ARRAY[]::TEXT[], NULL),
    ('SPH-W 113', 'BACKPACKING', '10124', 'Class Status', 'W Wednesday 6:40 PM–9:10 PM', 'EG 020', 'Hannah McConnell, Niccole Brown', 5, NULL, 'Activity', '2', 'EIGENMANN HALL', ARRAY[]::TEXT[], 'Designed to introduce the basics of backpacking and backcountry camping, proper equipment selection, topographic map use, water purification, campsite selection, and Leave No Trace ethics. A highly experience-based course where students will engage in a weekend field experience involving group dynamics, genuine reflection, and new skill demonstration. More information: outdoors.iu.edu/academics', ARRAY[]::TEXT[], NULL),
    ('SPH-W 113', 'BACKPACKING', '29871', 'Closed', 'M Monday 6:40 PM–9:10 PM', 'EG 020', 'Niccole Brown, Hannah McConnell', 0, NULL, 'Activity', '2', 'EIGENMANN HALL', ARRAY[]::TEXT[], 'Designed to introduce the basics of backpacking and backcountry camping, proper equipment selection, topographic map use, water purification, campsite selection, and Leave No Trace ethics. A highly experience-based course where students will engage in a weekend field experience involving group dynamics, genuine reflection, and new skill demonstration. More information: outdoors.iu.edu/academics', ARRAY[]::TEXT[], NULL),
    ('SPH-W 114', 'MINDFULNESS IN THE OUTDOORS', '14169', 'Class Status', NULL, 'WB WEB', 'Niccole Brown, Hannah McConnell, Danielle Nolan', 2, NULL, 'Activity', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Designed to reconnect students with the outdoors and disconnect from technology. Students learn tools to bring peace, relaxation, and calmness into their life. This course includes hiking, yoga, breathing exercises, and meditations. The hybrid model consists of online, asynchronous content and a single day, in-person field experience. More information: outdoors.iu.edu/academics', ARRAY[]::TEXT[], NULL),
    ('SPH-W 114', 'MINDFULNESS IN THE OUTDOORS', '11606', 'Closed', NULL, 'WB WEB', 'Niccole Brown, Hannah McConnell, Danielle Nolan', 0, NULL, 'Activity', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Designed to reconnect students with the outdoors and disconnect from technology. Students learn tools to bring peace, relaxation, and calmness into their life. This course includes hiking, yoga, breathing exercises, and meditations. The hybrid model consists of online, asynchronous content and a single day, in-person field experience. More information: outdoors.iu.edu/academics', ARRAY[]::TEXT[], NULL),
    ('SPH-W 116', 'WILDERNESS FIRST AID', '4232', 'Class Status', 'SaSu Saturday, Sunday 8:30 AM–5:00 PM', 'HD TBA', 'Hannah McConnell, Niccole Brown, Danyele Green, Tymme Laun', 6, NULL, 'Lecture', '1', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Designed to introduce the basics of wilderness emergency medicine by combining both hands-on learning and classroom instruction. Content includes response to environmental emergencies, soft tissue and musculoskeletal injuries, and patient assessment and care. Students who successfully complete this class will obtain a Wilderness First Aid certification. More information: outdoors.iu.edu/academics', ARRAY[]::TEXT[], NULL),
    ('SPH-W 116', 'WILDERNESS FIRST AID', '8831', 'Class Status', 'SaSu Saturday, Sunday 8:30 AM–5:00 PM', 'HD TBA', 'Niccole Brown, Hannah McConnell, Tymme Laun, Danyele Green', 4, NULL, 'Lecture', '1', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Designed to introduce the basics of wilderness emergency medicine by combining both hands-on learning and classroom instruction. Content includes response to environmental emergencies, soft tissue and musculoskeletal injuries, and patient assessment and care. Students who successfully complete this class will obtain a Wilderness First Aid certification. More information: outdoors.iu.edu/academics', ARRAY[]::TEXT[], NULL),
    ('SPH-W 125', 'INTRODUCTION TO MOUNTAIN BIKING', '10125', 'Class Status', 'M Monday 6:40 PM–9:10 PM', 'EG 020', 'Kate Nolan, Niccole Brown, Hannah McConnell', 1, NULL, 'Activity', '1', 'EIGENMANN HALL', ARRAY[]::TEXT[], 'Designed to introduce the foundational knowledge and techniques of mountain biking. Students will learn proper trail use and the fundamentals of off-road riding. Participation is through experiential learning and demonstration of new skills in field-based experiences. More information: outdoors.iu.edu/academics', ARRAY[]::TEXT[], NULL),
    ('SPH-W 132', 'CANOEING', '8832', 'Class Status', 'Tu Tuesday 6:40 PM–9:10 PM', 'EG 020', 'Hannah McConnell, Niccole Brown', 2, NULL, 'Activity', '2', 'EIGENMANN HALL', ARRAY[]::TEXT[], 'Designed to introduce the basics of canoeing, including paddle strokes, essential maneuvers, basic canoe rescues, and Leave No Trace ethics. A highly experience-based course where students will engage in a weekend field experience involving group dynamics, genuine reflection, and new skill demonstration. More information: outdoors.iu.edu/academics', ARRAY[]::TEXT[], NULL),
    ('SPH-W 135', 'WHITEWATER KAYAKING', '13565', 'Class Status', 'Tu Tuesday 6:40 PM–9:10 PM', 'EG 020', 'Niccole Brown, Hannah McConnell', 1, NULL, 'Activity', '2', 'EIGENMANN HALL', ARRAY[]::TEXT[], 'This course is designed to introduce essential techniques required in whitewater kayaking, including kayaking strategies and tactics, water safety, river dynamics, and relevant whitewater kayaking equipment. A highly experience-based course where students engage in a weekend field experience involving group dynamics, genuine reflection, and new skill demonstration. More information: outdoors.iu.edu/academics', ARRAY[]::TEXT[], NULL),
    ('SPH-W 136', 'COASTAL KAYAKING', '9346', 'Class Status', 'M Monday 6:40 PM–9:10 PM', 'EG 020', 'Hannah McConnell, Niccole Brown', 4, NULL, 'Activity', '2', 'EIGENMANN HALL', ARRAY[]::TEXT[], 'Designed to introduce the techniques for kayaking on protected waters, including paddle strokes, maneuvers, wet exits, kayak rescues, navigation, equipment, safety, planning, and Leave No Trace ethics. An experiential course where students will engage in a weekend field experience involving group dynamics, reflection, and new skill demonstration. More information: outdoors.iu.edu/academics', ARRAY[]::TEXT[], NULL),
    ('SPH-W 144', 'ROCK CLIMBING', '8833', 'Class Status', 'Tu Tuesday 6:40 PM–9:10 PM', 'EG 020', 'Hannah McConnell, Niccole Brown', 3, NULL, 'Activity', '2', 'EIGENMANN HALL', ARRAY[]::TEXT[], 'Designed to introduce the basics of outdoor rock climbing including belaying techniques, gear selection, climbing partner communication, general movement on rock, as well as hand and foot placements. An experiential course where students engage in a weekend field experience involving group dynamics, reflection, and new skill demonstration. More information: outdoors.iu.edu/academics', ARRAY[]::TEXT[], NULL),
    ('SPH-W 144', 'ROCK CLIMBING', '8834', 'Class Status', 'M Monday 6:40 PM–9:10 PM', 'EG 020', 'Hannah McConnell, Niccole Brown', 2, NULL, 'Activity', '2', 'EIGENMANN HALL', ARRAY[]::TEXT[], 'Designed to introduce the basics of outdoor rock climbing including belaying techniques, gear selection, climbing partner communication, general movement on rock, as well as hand and foot placements. An experiential course where students engage in a weekend field experience involving group dynamics, reflection, and new skill demonstration. More information: outdoors.iu.edu/academics', ARRAY[]::TEXT[], NULL),
    ('SPH-W 305', 'INTRODUCTION TO OUTDOOR LEADERSHIP', '8835', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:55 PM', 'EG 020', 'Niccole Brown, Hannah McConnell, Tim Street', 5, NULL, 'Lecture', '3', 'EIGENMANN HALL', ARRAY[]::TEXT[], 'Designed to introduce the foundations of outdoor adventure leadership, including core competencies of outdoor living skills, education, leadership, risk management, environmental integration, planning and logistics. The course emphasizes backcountry leadership and judgement with a broad overview of the relevant theories and practices of the outdoor adventure industry. More information: outdoors.iu.edu/academics', ARRAY[]::TEXT[], NULL),
    ('SPH-W 331', 'WILDERNESS FIRST RESPONDER', '8836', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–7:55 PM', 'HD TBA', 'David Calvin, Hannah McConnell, Niccole Brown', 7, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'The Wilderness First Responder (WFR) course is the most widely accepted standard in wilderness medical care for professional outdoor leaders including mountain and river guides, wilderness trip leaders, expedition leaders, camp and outing club leaders and rangers; anyone who is responsible for the safety and care of a group of people in the backcountry. The curriculum uses the principles of long-term care, improvised resources and varying environmental conditions as the framework for learning. The course was created to provide outdoor leaders and adventurers with the knowledge and skills needed to deal with emergencies in remote settings. The course takes an in-depth look at the underlying physiology of common and uncommon emergencies that might be encountered in the wilderness context. It goes well beyond most first aid courses, particularly those that are oriented to ''urban/street medicine.'' The primary components of the course include personal/group safety & hygiene, backcountry survival, anatomy and physiology, pathophysiology, patient assessment, documentation, trauma medical emergencies, environmental emergencies, long-term care, teamwork, organizing/improvising rescues, decision-making, leadership, judgment and prevention.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 610', 'PROFESSIONAL DEVELOPMENT SEMINAR 1', '9133', 'Class Status', 'Tu Tuesday 9:35 AM–10:50 AM', 'ED 1230', 'Susan Simmons', 5, NULL, 'Lecture', '2', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The course will provide students in the MPH program with skills in cultural assessment, cultural competence and interprofessional team work. Students will develop diverse skill sets in the above areas through hands-on activities. Students will be required to apply knowledge gained to the development of cultural appropriate programs/policies and communication.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 610', 'PROFESSIONAL DEVELOPMENT SEMINAR 1', '9134', 'Class Status', NULL, 'WB WEB', 'Jeanne Johnston', 60, NULL, 'Lecture', '2', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The course will provide students in the MPH program with skills in cultural assessment, cultural competence and interprofessional team work. Students will develop diverse skill sets in the above areas through hands-on activities. Students will be required to apply knowledge gained to the development of cultural appropriate programs/policies and communication.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 650', 'EVIDENCE-BASED APPROACHES TO PUBLIC HEALTH', '10437', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'GY 1050', 'Juhua Luo', 58, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Introduces basic epidemiological and biostatistical principles, concepts, and procedures for the surveillance and investigation of health-related states or events. Introduces planning a research study, collecting data and analyzing data to provide evidence leading to effective interventions and preventions.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 650', 'EVIDENCE-BASED APPROACHES TO PUBLIC HEALTH', '8555', 'Class Status', NULL, 'WB WEB', 'Erik Nelson', 56, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Introduces basic epidemiological and biostatistical principles, concepts, and procedures for the surveillance and investigation of health-related states or events. Introduces planning a research study, collecting data and analyzing data to provide evidence leading to effective interventions and preventions.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 660', 'POPULATION HEALTH DETERMINANTS', '10438', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'BH 118', 'Lucia Guerra Reyes', 8, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Analyzes health disparities and health equity from a socioecological perspective. Provides training in culturally competent public health communication. Introduces concepts in leadership and intervention design and prepares students to apply systems thinking to a public health issue.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 660', 'POPULATION HEALTH DETERMINANTS', '8556', 'Class Status', NULL, 'WB WEB', 'Lucia Guerra Reyes', 43, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Analyzes health disparities and health equity from a socioecological perspective. Provides training in culturally competent public health communication. Introduces concepts in leadership and intervention design and prepares students to apply systems thinking to a public health issue.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 695', 'PLANNING FOR THE MPH PROFESSIONAL PRACTICE EXPERIENCE', '33429', 'Class Status', NULL, NULL, 'Catherine Sherwood-Laughlin', 14, NULL, 'Seminar', '1', NULL, ARRAY[]::TEXT[], 'This course is designed to support students in the preparation for the PPE. Public health skills are developed through professional experiences in public health settings facilitated by preceptors and supervised by faculty, which students gain this experience in the Professional Practice Experience (PPE) course.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 695', 'PLANNING FOR THE MPH PROFESSIONAL PRACTICE EXPERIENCE', '33430', 'Class Status', NULL, NULL, 'Edlin Garcia', 16, NULL, 'Seminar', '1', NULL, ARRAY[]::TEXT[], 'This course is designed to support students in the preparation for the PPE. Public health skills are developed through professional experiences in public health settings facilitated by preceptors and supervised by faculty, which students gain this experience in the Professional Practice Experience (PPE) course.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 695', 'PLANNING FOR THE MPH PROFESSIONAL PRACTICE EXPERIENCE', '33431', 'Class Status', NULL, NULL, 'Jeanne Johnston', 14, NULL, 'Seminar', '1', NULL, ARRAY[]::TEXT[], 'This course is designed to support students in the preparation for the PPE. Public health skills are developed through professional experiences in public health settings facilitated by preceptors and supervised by faculty, which students gain this experience in the Professional Practice Experience (PPE) course.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 695', 'PLANNING FOR THE MPH PROFESSIONAL PRACTICE EXPERIENCE', '33432', 'Class Status', NULL, NULL, 'Ming Li', 20, NULL, 'Seminar', '1', NULL, ARRAY[]::TEXT[], 'This course is designed to support students in the preparation for the PPE. Public health skills are developed through professional experiences in public health settings facilitated by preceptors and supervised by faculty, which students gain this experience in the Professional Practice Experience (PPE) course.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 695', 'PLANNING FOR THE MPH PROFESSIONAL PRACTICE EXPERIENCE', '33433', 'Class Status', NULL, NULL, 'William Ramos', 14, NULL, 'Seminar', '1', NULL, ARRAY[]::TEXT[], 'This course is designed to support students in the preparation for the PPE. Public health skills are developed through professional experiences in public health settings facilitated by preceptors and supervised by faculty, which students gain this experience in the Professional Practice Experience (PPE) course.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 695', 'PLANNING FOR THE MPH PROFESSIONAL PRACTICE EXPERIENCE', '33434', 'Class Status', NULL, NULL, 'Maria Parker', 12, NULL, 'Seminar', '1', NULL, ARRAY[]::TEXT[], 'This course is designed to support students in the preparation for the PPE. Public health skills are developed through professional experiences in public health settings facilitated by preceptors and supervised by faculty, which students gain this experience in the Professional Practice Experience (PPE) course.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 696', 'PROFESSIONAL PRACTICE EXPERIENCE IN PUBLIC HEALTH', '9766', 'Class Status', NULL, NULL, 'Catherine Sherwood-Laughlin', 18, NULL, 'Practicum', '3', NULL, ARRAY[]::TEXT[], 'This course will cover topics related to professional practice opportunities. The primary purpose of these experiences is to provide the student with hands-on experiences in public health which can assist in developing desirable employment skills. Additionally student will produce a high-quality written product that is useful to an external agency.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 696', 'PROFESSIONAL PRACTICE EXPERIENCE IN PUBLIC HEALTH', '29772', 'Class Status', NULL, NULL, 'Edlin Garcia', 15, NULL, 'Practicum', '3', NULL, ARRAY[]::TEXT[], 'This course will cover topics related to professional practice opportunities. The primary purpose of these experiences is to provide the student with hands-on experiences in public health which can assist in developing desirable employment skills. Additionally student will produce a high-quality written product that is useful to an external agency.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 696', 'PROFESSIONAL PRACTICE EXPERIENCE IN PUBLIC HEALTH', '29774', 'Class Status', NULL, NULL, 'Jeanne Johnston', 20, NULL, 'Practicum', '3', NULL, ARRAY[]::TEXT[], 'This course will cover topics related to professional practice opportunities. The primary purpose of these experiences is to provide the student with hands-on experiences in public health which can assist in developing desirable employment skills. Additionally student will produce a high-quality written product that is useful to an external agency.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 696', 'PROFESSIONAL PRACTICE EXPERIENCE IN PUBLIC HEALTH', '29778', 'Class Status', NULL, NULL, 'William Ramos', 17, NULL, 'Practicum', '3', NULL, ARRAY[]::TEXT[], 'This course will cover topics related to professional practice opportunities. The primary purpose of these experiences is to provide the student with hands-on experiences in public health which can assist in developing desirable employment skills. Additionally student will produce a high-quality written product that is useful to an external agency.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 696', 'PROFESSIONAL PRACTICE EXPERIENCE IN PUBLIC HEALTH', '29780', 'Class Status', NULL, NULL, 'Juhua Luo', 17, NULL, 'Practicum', '3', NULL, ARRAY[]::TEXT[], 'This course will cover topics related to professional practice opportunities. The primary purpose of these experiences is to provide the student with hands-on experiences in public health which can assist in developing desirable employment skills. Additionally student will produce a high-quality written product that is useful to an external agency.', ARRAY[]::TEXT[], NULL),
    ('SPH-X 696', 'PROFESSIONAL PRACTICE EXPERIENCE IN PUBLIC HEALTH', '29782', 'Class Status', NULL, NULL, 'Maria Parker', 20, NULL, 'Practicum', '3', NULL, ARRAY[]::TEXT[], 'This course will cover topics related to professional practice opportunities. The primary purpose of these experiences is to provide the student with hands-on experiences in public health which can assist in developing desirable employment skills. Additionally student will produce a high-quality written product that is useful to an external agency.', ARRAY[]::TEXT[], NULL),
    ('SPH-Y 225', 'DISABILITY, HEALTH, AND FUNCTION', '5510', 'Class Status', 'MWF Monday, Wednesday, Friday 8:00 AM–8:50 AM', 'BH 304', 'Jordan McIntire', 8, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Students will be provided with a model of disabling conditions including physical, mental, developmental, intellectual, hearing and vision, and other disabilities related to aging. Content will focus on etiology, prognosis, symptomatic conditions, prevalence, and its relationship to public health. Models of disability and medical terminology will be covered.', ARRAY[]::TEXT[], NULL),
    ('SPH-Y 378', 'RECREATIONAL THERAPY ASSESSMENT AND PLANNING', '9069', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'AC C102', 'Jordan McIntire', 4, 'Lecture', 'Lecture', '4', 'CEDAR HALL', ARRAY[]::TEXT[], 'This class is the first in a two-part series to learn appropriate treatment skills for the entry-level recreational therapist. This is a service learning class, and the laboratory section must be taken simultaneously in order to receive credit for the class.', ARRAY[]::TEXT[], NULL),
    ('SPH-Y 378', 'RECREATIONAL THERAPY ASSESSMENT AND PLANNING', '9070', 'Class Status', 'Tu Tuesday 11:30 AM–12:45 PM', 'SE 245', 'Jordan McIntire', 4, 'Laboratory', 'Lecture', '4', 'CEDAR HALL', ARRAY[]::TEXT[], 'This class is the first in a two-part series to learn appropriate treatment skills for the entry-level recreational therapist. This is a service learning class, and the laboratory section must be taken simultaneously in order to receive credit for the class.', ARRAY[]::TEXT[], NULL),
    ('SPH-Y 397', 'RECREATIONAL THERAPY INTERNSHIP AND PROFESSIONAL PREPARATION', '5623', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'AC C102', 'Jared Allsop', 23, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'This course is designed to prepare students for their required professional internship through a review of skills, consideration of the best placement for their career goals, and planning for the job search. Professional preparatory skills will also be developed and honed.', ARRAY[]::TEXT[], NULL),
    ('SPH-Y 470', 'CONTEMPORARY ISSUES IN RECREATIONAL THERAPY', '2009', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'LI 028', 'Jordan McIntire', 16, NULL, 'Lecture', '3', 'WELLS LIBRARY', ARRAY[]::TEXT[], 'This course is designed to advance the student''s knowledge of issues and concerns that influence the provision of recreational therapy services and the advancement of the profession. Students are required critically to examine and discuss issues impacting the health care field.', ARRAY[]::TEXT[], NULL),
    ('SPH-Y 560', 'PROFESSIONAL DEVELOPMENT OF RECREATIONAL THERAPY', '8456', 'Class Status', NULL, 'WB WEB', 'Blair McKissock', 12, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is designed to advance the student''s knowledge of issues and concerns that influence the provision of therapeutic recreation services. This course will require the student to critically examine and discuss issues impacting the profession of therapeutic recreation in order to develop a sound, practical philosophy.', ARRAY[]::TEXT[], NULL),
    ('SPH-Y 561', 'SOCIAL PSYCHOLOGY OF RECREATIONAL THERAPY', '10624', 'Class Status', NULL, 'WB WEB', 'Jared Allsop', 11, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is intended to provide an overview of the social psychology of disability with specific application to recreational therapy. Students will learn to view a client''s health condition through the lens of social psychological constructs and theories to better create specific goals within the practice of recreational therapy.', ARRAY['Class uses IU eTexts'], NULL),
    ('STAT-G 901', 'ADVANCED RESEARCH', '6381', 'Class Status', NULL, NULL, 'Daniel Manrique-Vallier', 1, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 211', 'STATISTICS FOR JOURNALISTS', '6310', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PY 101', 'Paul Hunt', 8, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Essential statistical concepts and tools for journalists in the age of data, including probability, graphics, descriptive statistics, prediction, study design, comparison, testing, and estimation. The course has a heavier emphasis on writing and reading media reports than other introductory statistics courses.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
