    ('STAT-S 303', 'APPLIED STATISTICAL METHODS FOR THE LIFE SCIENCES', '6127', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'GA 0001', 'Pulindu Ratnasekera', 3, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduction to methods for analyzing data arising in the life sciences, designed for Biology, Human Biology, and pre-medical students. Graphical and numerical descriptions of data, probability models, fundamental principles of estimation and hypothesis testing, inferences about means, correlation, linear regression.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('STAT-S 303', 'APPLIED STATISTICAL METHODS FOR THE LIFE SCIENCES', '10128', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GY 1045', 'Pulindu Ratnasekera', 4, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduction to methods for analyzing data arising in the life sciences, designed for Biology, Human Biology, and pre-medical students. Graphical and numerical descriptions of data, probability models, fundamental principles of estimation and hypothesis testing, inferences about means, correlation, linear regression.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('STAT-S 350', 'INTRODUCTION TO STATISTICAL INFERENCE', '8084', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'SB 150', 'Maoran Xu', 7, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Explores the formulation of statistical inference using probability models. Addresses point estimation, hypothesis testing, and set estimation for various models, including 1-, 2-, and K-sample location problems, goodness-of-fit, correlation and regression.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('STAT-S 350', 'INTRODUCTION TO STATISTICAL INFERENCE', '9453', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'GY 1045', 'Fangzheng Xie', 10, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Explores the formulation of statistical inference using probability models. Addresses point estimation, hypothesis testing, and set estimation for various models, including 1-, 2-, and K-sample location problems, goodness-of-fit, correlation and regression.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('STAT-S 352', 'DATA MODELING AND INFERENCE', '8894', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'BH 006', 'Jianyu Wang', 20, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Intermediate-level survey of resampling, likelihood, and Bayesian methods of statistical inference. Distributional models of various data types. Categorical, count, time-to-event, time series, linear models, and hierarchical regression models.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 426', 'BAYESIAN THEORY AND DATA ANALYSIS', '8888', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 206', 'Daniel Manrique-Vallier', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduces the theory and practice of Bayesian inference. Explores prior and posterior probability distributions. Addresses data collection, model formulation, computation, model checking, and sensitivity analysis.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 431', 'APPLIED LINEAR MODELS I', '4254', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WY 101', 'Arturo Valdivia', 0, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'Part I of a two-semester sequence on linear models. Presents the analysis of simple and multiple linear regression in the presence of simple and complex regressors. Introduces transformations, regression diagnostics, influence analysis, and regression shrinkage methods.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 470', 'EXPLORATORY DATA ANALYSIS', '7793', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'WH 111', 'Brad Luen', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Techniques for summarizing and displaying data. Exploration versus confirmation. Connections with conventional statistical analysis and data mining. Applications to large data sets.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 475', 'STATISTICAL LEARNING AND HIGH DIMENSIONAL DATA ANALYSIS', '29470', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 214', 'Michael Trosset', 10, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Explores the structure of high-dimensional data through data-analytic methods. Covers graphical methods, linear and nonlinear dimension reduction techniques, manifold learning and supervised, semi-supervised, and unsupervised learning.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 519', 'A GENTLE INTRODUCTION TO STATISTICS IN R', '12686', 'Class Status', NULL, 'WB WEB', 'Arturo Valdivia', 19, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introduces basic concepts of probability and statistical inference through careful study of several important procedures. Topics include discrete and continuous random variables, estimation, hypothesis testing, 1- and 2-sample location problems, ANOVA and simple linear regression. Assignments involve applying probability models and/or statistical methods to practical situations and/or actual data sets.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 520', 'INTRODUCTION TO STATISTICS', '7640', 'Class Status', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'LU 1001', 'Yichi Zhang', 50, NULL, 'Lecture', '3', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'Basic concepts of data analysis and statistical inference, applied to 1-sample and 2-sample location problems, the analysis of variance, and linear regression. Probability models and statistical methods applied to practical situations and actual data sets from various disciplines. Elementary statistical theory, including the plug-in principle, maximum likelihood, and the method of least squares.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 520', 'INTRODUCTION TO STATISTICS', '8193', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'WH 111', 'Nathan Glatt-Holtz', 51, NULL, 'Lecture', '3', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'Basic concepts of data analysis and statistical inference, applied to 1-sample and 2-sample location problems, the analysis of variance, and linear regression. Probability models and statistical methods applied to practical situations and actual data sets from various disciplines. Elementary statistical theory, including the plug-in principle, maximum likelihood, and the method of least squares.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 520', 'INTRODUCTION TO STATISTICS', '11702', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 304', 'Nathan Glatt-Holtz', 25, NULL, 'Lecture', '3', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'Basic concepts of data analysis and statistical inference, applied to 1-sample and 2-sample location problems, the analysis of variance, and linear regression. Probability models and statistical methods applied to practical situations and actual data sets from various disciplines. Elementary statistical theory, including the plug-in principle, maximum likelihood, and the method of least squares.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 520', 'INTRODUCTION TO STATISTICS', '5972', 'Class Status', NULL, 'WB WEB', 'Jianyu Wang', 38, NULL, 'Lecture', '3', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'Basic concepts of data analysis and statistical inference, applied to 1-sample and 2-sample location problems, the analysis of variance, and linear regression. Probability models and statistical methods applied to practical situations and actual data sets from various disciplines. Elementary statistical theory, including the plug-in principle, maximum likelihood, and the method of least squares.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 610', 'INTRODUCTION TO STATISTICAL COMPUTING', '9105', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 307 SW 220', 'Julia Fukuyama', 17, NULL, 'Lecture', '3', 'BALLANTINE HALL, SWAIN WEST', ARRAY[]::TEXT[], 'Introduction to R from a software engineering perspective and an introduction to algorithms commonly used in applied statistics. Optimization algorithms including gradient descent, stochastic gradient descent, the EM algorithm, and topics in convex optimization. Stochastic algorithms including rejection sampling, Metropolis-Hastings, and Gibbs sampling.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 621', 'FUNDAMENTALS OF STATISTICAL METHODS AND THEORY I', '9850', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'SW 103', 'Jianyu Wang', 4, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Part 1 of a 2-semester sequence on fundamental concepts, principles, and techniques of probabilistic/statistical inference. Random variables and probability distributions, expectation, limit laws, parametric vs nonparametric inference, Bayesian vs frequentist inference, point estimation, hypothesis testing, confidence sets, simulation.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 626', 'BAYESIAN THEORY AND DATA ANALYSIS', '8889', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 206', 'Daniel Manrique-Vallier', 9, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to the theory and practice of Bayesian inference. Prior and posterior probability distributions. Data collection, model formulation, computation, model checking, sensitivity analysis.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 631', 'APPLIED LINEAR MODELS I', '4431', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WY 101', 'Arturo Valdivia', 0, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'Part I of a 2-semester sequence on linear models, emphasizing linear regression and the analysis of variance, including topics from the design of experiments and culminating in the general linear model.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 670', 'EXPLORATORY DATA ANALYSIS', '7794', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'WH 111', 'Brad Luen', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Numerical and graphical techniques for summarizing and displaying data. Exploration versus confirmation. Connections with conventional statistical analysis and data mining. Applications to large data sets.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 675', 'STATISTICAL LEARNING: HIGH-DIMENSIONAL DATA ANALYSIS', '29471', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 214', 'Michael Trosset', 10, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Data analytic methods for exploring the structure of high-dimensional data. Graphical methods, linear and nonlinear dimension reduction techniques, manifold learning. Supervised, semi-supervised, and unsupervised learning.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 690', 'STATISTICAL CONSULTING', '5511', 'Closed', 'Tu Tuesday 3:55 PM–6:25 PM', 'SE 220', 'Julia Fukuyama', 0, NULL, 'Lecture', '4', 'SWAIN EAST', ARRAY[]::TEXT[], 'Development of effective consulting skills, including the conduct of consulting sessions, collaborative problem-solving, using professional resources, and preparing verbal and written reports. Interactions with clients will be coordinated by the Indiana Statistical Consulting Center.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 692', 'INTERNSHIP IN STATISTICAL CONSULTING', '7821', 'Class Status', NULL, 'WB WEB', 'Staff', 4, NULL, 'Internship', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'One-semester internship at the Indiana Statistical Consulting Center (ISCC). Students work on actual consulting problems under the direct supervision of professional statisticians.', ARRAY[]::TEXT[], NULL),
