    ('STAT-S 695', 'READINGS IN STATISTICS', '30350', 'Class Status', NULL, NULL, 'Yichi Zhang', 2, NULL, 'Readings', '1–3', NULL, ARRAY[]::TEXT[], 'Supervised reading of a topic in statistics.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 785', 'SEMINAR ON STATISTICAL THEORY', '6422', 'Class Status', 'W Wednesday 12:00 PM–2:30 PM', 'SE 220', 'Michael Trosset', 5, NULL, 'Seminar', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'Professional development for Ph.D. students in statistics. Topics in statistical theory will be used to provide students with experience in preparing presentations, posters, referee reports, grant proposals, etc.', ARRAY[]::TEXT[], NULL),
    ('STAT-S 799', 'RESEARCH IN STATISTICS', '4397', 'Class Status', NULL, NULL, 'Michael Trosset', 10, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Research in statistics.', ARRAY[]::TEXT[], NULL),
