    ('SWK-S 481', 'SOCIAL WORK PRACTICUM I', '13303', 'Closed', 'Tu Tuesday 9:10 AM–11:55 AM', 'AH C1020B', 'Nordia McNish', 0, NULL, 'Practicum', '6', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'The BSW practicum integrates theory, skills, and values, fostering competency through agency-based experience. S481 provides 200 hours of supervised practice, where students apply knowledge, engage with clients, utilize resources, collaborate with professionals, and address systemic oppression, ensuring they meet CSWE competency standards while gaining real-world social work experience.', ARRAY[]::TEXT[], NULL),
    ('SWK-S 490', 'INDEPENDENT STUDY', '7639', 'Class Status', NULL, NULL, 'Michael Ross', 2, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Intensive study of specific areas relative to social work profession and practice.', ARRAY[]::TEXT[], NULL),
    ('SWK-S 502', 'EVIDENCE-INFORMED INQUIRY FOR PRACTICE', '8113', 'Class Status', 'Tu Tuesday 9:10 AM–11:55 AM', 'AH C2038', 'Kimberly Johnson', 3, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This foundation research course assists students in developing the knowledge, skills, and values necessary to evaluate studies testing the effectiveness of social work practice. Emphasis is placed upon knowledge of qualitative and quantitative designs, methods, and techniques that inform students of best practices in social work. Students will recognize the impact of ethnicity, gender, age, and sexual orientation on the research process and be able to critically review published studies with attention to bias in research.', ARRAY['Class uses IU eTexts'], NULL),
    ('SWK-S 505', 'SOCIAL POLICY ANALYSIS AND PRACTICE', '8922', 'Class Status', 'Tu Tuesday 12:45 PM–3:30 PM', 'AH C1001', 'Jessica Adams', 10, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course examines the processes that influence the development of social policy and social services. Included are legislative and political processes, models of policy analysis, service delivery and policy implementation. Effects of these on people are considered from global, political, economic, environmental and social policy perspectives. This course is developed around the general proposition that social workers utilize knowledge and skills to carry out roles and functions critical for practice. Such knowledge and skills include the application of social policy analysis, the legislative process, the role and impact of politics and political choice on the quality of life of people, and the effect of economic-social policy decision and judicial actions on social services. In addition, the course examines the variability of the common and uncommon attributes of service delivery systems.', ARRAY['Class uses IU eTexts'], NULL),
    ('SWK-S 506', 'FOUNDATIONS OF ETHICAL SOCIAL WORK PRACTICE', '30563', 'Class Status', 'M Monday 12:45 PM–3:30 PM', 'AH C2038', 'Michelle Whitaker', 3, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course introduces the history, mission, and legal foundations of the social work profession. It covers fields of practice, ethical frameworks, professional conduct, critical thinking, self-awareness, and self-care-providing students with foundational knowledge and skills essential for competent and responsible social work practice.', ARRAY['Class uses IU eTexts'], NULL),
    ('SWK-S 507', 'DIVERSITY, HUMAN RIGHTS, AND SOCIAL JUSTICE', '30248', 'Class Status', 'M Monday 3:55 PM–6:40 PM', 'AH C1023', 'Jessica Adams', 1, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course will introduce MSW students to human rights and social justice perspectives in order to examine the shifting landscape of diversity, oppression, power, and privilege. The fundamental goal of the course is for students to develop critical consciousness in order to gain competencies to address diversity, privilege and oppression in social work practice. The importance of power and the dynamics of domination and subordination in multiple manifestations of oppression, particularly among historically oppressed groups, will be explored. An understanding of these concepts integrated with an understanding of one''s self within these systems is essential for social work practice. This course will employ a practice framework that integrates 1) a human rights perspective promoting the dignity, respect, and well-being of all persons; 2) a social justice perspective aiming to understand and ameliorate oppression, unequal access to resources, and social inequities; 3) and diversity and cultural humility, which requires critical self-evaluation and self-awareness in order to address power and privilege and to develop respectful cultural sensitivity. Students will utilize this practice framework to address social injustice through analysis, self-reflection, and peer collaboration. The course will serve as a transformational space for students and instructors to cultivate and exercise cultural humility when exploring how multiple identities shape our beliefs, assumptions, biases, behaviors, and life experiences. It will challenge and deconstruct assumptions within theories and research methodologies relevant to social work in order to understand the dynamics that manage and sustain oppression at individual and institutional levels. This course will examine how oppression and intersectionality affect service delivery at micro and macro levels, and how a human rights framework integrated with cultural humility ameliorates social injustice and promotes culturally responsive services. This course will promote students'' career-long process of fostering cultural humility and applying an understanding of human rights, diversity, and oppression to their practice with individuals, families, groups, organizations, communities, and society.', ARRAY[]::TEXT[], NULL),
    ('SWK-S 508', 'GENERALIST THEORY AND PRACTICE', '10525', 'Class Status', 'Tu Tuesday 3:55 PM–6:40 PM', 'AH C1020', 'Shaleen Guthrie', 5, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course focuses on reciprocal relationships between human behavior and the social environment with selected theoretical perspectives and their associated empirically-based theories, including strengths/empowerment, ecological/systems, behavioral, critical, and developmental perspectives and theories. Learners will use micro interviewing skills to apply these perspectives and theories throughout the planned change process to service diverse client needs and experiences. The integration of theory and practice through the planned change process will be guided by the biopsychosocial and spiritual perspective.', ARRAY['Class uses IU eTexts'], NULL),
    ('SWK-S 517', 'ASSESSMENT IN MENTAL HEALTH AND ADDICTIONS', '30255', 'Class Status', 'Th Thursday 9:10 AM–11:55 AM', 'AH C1022', 'Tammi Nelson', 1, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Recognizing the social, political, legal, and ethical implications of assessment, students enrolled in this course critically examine various conceptual frameworks and apply bio-psychosocial and strengths perspectives to understand its multidimensional aspects. Students learn to conduct sophisticated mental status and lethality risk interviews, engage in strengths and assets discovery, assess for drugs of abuse, understand types of psychotropic medications, their uses, and related side effects, and apply the Diagnostic and Statistical Manual of the American Psychiatric Association and other classification schemes in formulating assessment hypotheses. They gain an understanding of the application of several relevant assessment instruments and learn to evaluate their relevance for service to at-risk populations, including persons affected by mental health issues, substance use disorders, and other behavioral addictions. Students learn to collaborate with a diverse range of consumers and other professionals in developing meaningful assessments upon which to plan goals, intervention strategies, and means for evaluation.', ARRAY[]::TEXT[], NULL),
    ('SWK-S 517', 'ASSESSMENT IN MENTAL HEALTH AND ADDICTIONS', '35632', 'Class Status', 'Th Thursday 9:10 AM–11:55 AM', 'AH C2038', 'Lynell Cooper', 2, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Recognizing the social, political, legal, and ethical implications of assessment, students enrolled in this course critically examine various conceptual frameworks and apply bio-psychosocial and strengths perspectives to understand its multidimensional aspects. Students learn to conduct sophisticated mental status and lethality risk interviews, engage in strengths and assets discovery, assess for drugs of abuse, understand types of psychotropic medications, their uses, and related side effects, and apply the Diagnostic and Statistical Manual of the American Psychiatric Association and other classification schemes in formulating assessment hypotheses. They gain an understanding of the application of several relevant assessment instruments and learn to evaluate their relevance for service to at-risk populations, including persons affected by mental health issues, substance use disorders, and other behavioral addictions. Students learn to collaborate with a diverse range of consumers and other professionals in developing meaningful assessments upon which to plan goals, intervention strategies, and means for evaluation.', ARRAY[]::TEXT[], NULL),
    ('SWK-S 519', 'COMMUNITY AND GLOBAL THEORY AND PRACTICE', '30257', 'Class Status', 'Th Thursday 12:45 PM–3:30 PM', 'AH C1022', 'Michael Ross', 2, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course aims to build competencies in the areas of theory and practice, preparing students to work with communities in a global context. With local communities facing increased global socio-economic and political forces, community constituents, especially marginalized groups, are facing unprecedented challenges ranging from widespread increases in refugee migration, poverty, human trafficking, substance abuse, natural disasters, gender violence, civil conflict and wars. More than ever, social work professionals need to understand global issues and their impact on local communities, and be ready to design appropriate and effective interventions for community and global practice. Building on the core values of the social work profession, this course consists of five major topics: 1) Macro-practice and international social development; 2) Civil society and local capacity building; 3) Local and international agencies and legal frameworks; and 4) International social work community practice in different contexts (from global to local); and 5) Cultural relativism and the power of a rights-based discourse to affect positive change in global communities.', ARRAY['Class uses IU eTexts'], NULL),
    ('SWK-S 519', 'COMMUNITY AND GLOBAL THEORY AND PRACTICE', '35631', 'Class Status', 'Th Thursday 12:45 PM–3:30 PM', 'AH C2038', 'Molly Weiler', 3, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course aims to build competencies in the areas of theory and practice, preparing students to work with communities in a global context. With local communities facing increased global socio-economic and political forces, community constituents, especially marginalized groups, are facing unprecedented challenges ranging from widespread increases in refugee migration, poverty, human trafficking, substance abuse, natural disasters, gender violence, civil conflict and wars. More than ever, social work professionals need to understand global issues and their impact on local communities, and be ready to design appropriate and effective interventions for community and global practice. Building on the core values of the social work profession, this course consists of five major topics: 1) Macro-practice and international social development; 2) Civil society and local capacity building; 3) Local and international agencies and legal frameworks; and 4) International social work community practice in different contexts (from global to local); and 5) Cultural relativism and the power of a rights-based discourse to affect positive change in global communities.', ARRAY['Class uses IU eTexts'], NULL),
    ('SWK-S 600', 'SEMINAR IN SOCIAL WORK', '12643', 'Class Status', 'Th Thursday 3:55 PM–6:40 PM', 'AH C1022', 'Kristin Hamre', 15, NULL, 'Seminar', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'The selection, assessment, and adaptation for social work of concepts, propositions and theories from the social psychological, and biological sciences.', ARRAY[]::TEXT[], NULL),
    ('SWK-S 600', 'SEMINAR IN SOCIAL WORK', '36898', 'Closed', NULL, 'WB WEB', 'Nicki Williamson', 0, NULL, 'Seminar', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'The selection, assessment, and adaptation for social work of concepts, propositions and theories from the social psychological, and biological sciences.', ARRAY[]::TEXT[], NULL),
    ('SWK-S 600', 'SEMINAR IN SOCIAL WORK', '36899', 'Closed', NULL, 'WB WEB', 'Sheila Dennis', 0, NULL, 'Seminar', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'The selection, assessment, and adaptation for social work of concepts, propositions and theories from the social psychological, and biological sciences.', ARRAY[]::TEXT[], NULL),
    ('SWK-S 613', 'SPECIALIZED INSTRUCTION AND SUPPORT SERVICES FOR DIVERSE STUDENT POPULATIONS', '36729', 'Closed', NULL, 'WB WEB', 'Alyssa Mitchem', 0, NULL, 'Seminar', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course introduces students to the school social worker''s role as a specialized instructional support personnel (SISP), whose task is to enhance the ability of every school child to learn to his or her capacity. Through the study of research, practice, and policy issues facing school children, especially those with exceptionalities, students in this course will learn to promote educational services and expand educational success for children with exceptionalities, their families, schools, and communities. Students will learn the imperative for multidisciplinary collaboration that advances student well-being and supportive school environments. Recognizing the influence of historical and cultural contexts, diversity and oppression as well as social and economic forces shaping educational experiences are examined, specifically focusing on the occurrence of educational disparities and academic outcomes. Students enrolled in the Master of Social Work Schools Concentration are required to take the course as part of the Schools Concentration curriculum requirements.', ARRAY[]::TEXT[], NULL),
    ('SWK-S 651', 'SWK PRACTICUM II', '15302', 'Class Status', 'F Friday 3:55 PM–6:40 PM', 'AH C1021', 'Jennifer Hammond', 7, NULL, 'Practicum', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Agency-based field experience for interpersonal practice concentration students.', ARRAY[]::TEXT[], NULL),
    ('SWK-S 651', 'SWK PRACTICUM II', '15303', 'Class Status', 'F Friday 3:55 PM–6:40 PM', 'AH C1023A', 'James Fries', 2, NULL, 'Practicum', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Agency-based field experience for interpersonal practice concentration students.', ARRAY[]::TEXT[], NULL),
    ('SWK-S 651', 'SWK PRACTICUM II', '15304', 'Class Status', 'F Friday 3:55 PM–6:40 PM', 'AH C1022', 'Katie Tremel', 2, NULL, 'Practicum', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Agency-based field experience for interpersonal practice concentration students.', ARRAY[]::TEXT[], NULL),
    ('SWK-S 651', 'SWK PRACTICUM II', '35826', 'Closed', NULL, 'WB WEB', 'Alyssa Mitchem', 0, NULL, 'Practicum', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Agency-based field experience for interpersonal practice concentration students.', ARRAY[]::TEXT[], NULL),
    ('SWK-S 683', 'COMMUNITY-BASED PRACTICE IN MENTAL HEALTH AND ADDICTION', '8451', 'Class Status', 'F Friday 9:10 AM–11:55 AM', 'AH C3053A', 'John Keesler', 1, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Students enrolled in this course will examine a wide range of community-based services provided for people with severe mental health and substance use disorders including co-occurring mental and substance use disorders. Special attention is given to strengths-based, consumer informed, and evidence-based prevention and treatment models. Content includes, but is not limited to, community-based services in areas of prevention, case management, supported employment, housing, illness management, family support services, dual disorder treatment, and peer support services. Students also examine a variety of issues involved in the provision of community-based services such as ethical and legal issues, quality and continuity of care, health disparities, cultural competency, organizational and financial factors, and other relevant policy and practice issues. Students will examine linkages between community based services and the advancement of human rights and social and economic justice for persons with mental illnesses and substance use disorders.', ARRAY[]::TEXT[], NULL),
    ('SWK-S 683', 'COMMUNITY-BASED PRACTICE IN MENTAL HEALTH AND ADDICTION', '8983', 'Closed', 'F Friday 9:10 AM–11:55 AM', 'AH C3051A', 'Michelle Whitaker', 0, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Students enrolled in this course will examine a wide range of community-based services provided for people with severe mental health and substance use disorders including co-occurring mental and substance use disorders. Special attention is given to strengths-based, consumer informed, and evidence-based prevention and treatment models. Content includes, but is not limited to, community-based services in areas of prevention, case management, supported employment, housing, illness management, family support services, dual disorder treatment, and peer support services. Students also examine a variety of issues involved in the provision of community-based services such as ethical and legal issues, quality and continuity of care, health disparities, cultural competency, organizational and financial factors, and other relevant policy and practice issues. Students will examine linkages between community based services and the advancement of human rights and social and economic justice for persons with mental illnesses and substance use disorders.', ARRAY[]::TEXT[], NULL),
    ('SWK-S 686', 'SOCIAL WORK PRACTICE: ADDICTIONS', '32892', 'Class Status', 'F Friday 12:45 PM–3:30 PM', 'AH C1020', 'Tammi Nelson', 1, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'The purpose of this course is to provide learners with knowledge and skills relevant to social work practice in prevention, intervention, and treatment of the coexistence of substance use disorders, mental health issues, and behavioral addictions. Students draw upon previous and concurrent learning experiences and integrate values, knowledge, and skills acquired in other social work courses with the knowledge, and skills characteristic of social work practice in the treatment of substance use disorders. The course assists students to develop an evidence-based understanding of the prevention, assessment, and treatment needs associated with social work practice principles, methods, skills, and psychopharmacology with diverse populations experiencing substance use and potential co-occurring mental health disorders. Students explore the relationships between and among substance use/mental disorders and socioeconomic status, race, ethnicity, culture, religion, gender, sexual orientation, age, physical and mental ability, and other socio-environmental factors of vulnerability. Consistent with strengths and ecosystems perspectives, students consider the impact of an individual''s neurochemistry, social environments, physical settings, community contexts, and political realities that support or inhibit the emergence of substance use disorders as well as the co-occurrence of mental health issues.', ARRAY[]::TEXT[], NULL),
    ('SWK-S 686', 'SOCIAL WORK PRACTICE: ADDICTIONS', '32893', 'Class Status', 'F Friday 12:45 PM–3:30 PM', 'AH C1022', 'Vanessa Parker', 3, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'The purpose of this course is to provide learners with knowledge and skills relevant to social work practice in prevention, intervention, and treatment of the coexistence of substance use disorders, mental health issues, and behavioral addictions. Students draw upon previous and concurrent learning experiences and integrate values, knowledge, and skills acquired in other social work courses with the knowledge, and skills characteristic of social work practice in the treatment of substance use disorders. The course assists students to develop an evidence-based understanding of the prevention, assessment, and treatment needs associated with social work practice principles, methods, skills, and psychopharmacology with diverse populations experiencing substance use and potential co-occurring mental health disorders. Students explore the relationships between and among substance use/mental disorders and socioeconomic status, race, ethnicity, culture, religion, gender, sexual orientation, age, physical and mental ability, and other socio-environmental factors of vulnerability. Consistent with strengths and ecosystems perspectives, students consider the impact of an individual''s neurochemistry, social environments, physical settings, community contexts, and political realities that support or inhibit the emergence of substance use disorders as well as the co-occurrence of mental health issues.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 108', 'DANCE PRACTICES I', '7494', 'Class Status', 'MWF Monday, Wednesday, Friday 1:05 PM–2:35 PM', 'TH A217', 'Elizabeth Shea', 7, NULL, 'Studio', '2', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Elemental explorations of modern and contemporary dance techniques focusing on current physical training practices and foundational vocabulary of the genre. Learning theory and somatic work are also introduced.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 109', 'CORE OF DANCE TECHNIQUE', '3429', 'Class Status', 'MWF Monday, Wednesday, Friday 1:05 PM–2:35 PM', 'GR 128', 'Robert Burden', 6, NULL, 'Lecture', '3', 'GRESHAM DINING HALL', ARRAY[]::TEXT[], 'Introduction to concert dance techniques, as well as stretching and strengthening skills to prepare for those techniques. Practice with emphasis on dance vocabulary and theory.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 121', 'IMPROVISATION FOR CONTEMPORARY DANCE I', '5964', 'Class Status', 'W Wednesday 10:00 AM–11:45 AM', 'TH A217', 'Selene Carter', 7, NULL, 'Lecture', '1', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Experiences in creative movement expression through participation in structured dance activities.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 154', 'BEGINNING TAP DANCE', '5825', 'Class Status', 'TuTh Tuesday, Thursday 9:05 AM–9:55 AM', 'TH A200', 'Robert Burden', 2, NULL, 'Activity', '1', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'An introduction to the technique and styles of tap dancing, emphasizing rhythmic accuracy and efficiency of movement. Course will include history and appreciation of tap dance.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 154', 'BEGINNING TAP DANCE', '13319', 'Closed', 'TuTh Tuesday, Thursday 1:00 PM–2:15 PM', 'TH A200', 'Sherilyn Foley', 0, NULL, 'Activity', '1', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'An introduction to the technique and styles of tap dancing, emphasizing rhythmic accuracy and efficiency of movement. Course will include history and appreciation of tap dance.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 156', 'INTRODUCTION TO JAZZ DANCE TECHNIQUE', '5967', 'Closed', 'TuTh Tuesday, Thursday 10:05 AM–10:55 AM', 'AD A350', 'Robert Burden', 0, NULL, 'Lecture', '1', 'AUDITORIUM', ARRAY[]::TEXT[], 'An introduction to the modern jazz style of movement as it integrates with sound biomechanical principles. Phrasing, dynamics, and other qualities will be discussed.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 211', 'DANCE PRACTICES III', '5965', 'Class Status', 'MTuThF Monday, Tuesday, Thursday, Friday 11:15 AM–12:45 PM', 'GR 127', 'Beatrice Capote, kate lyons, Utam Moses', 12, NULL, 'Lecture', '3', 'GRESHAM DINING HALL', ARRAY[]::TEXT[], 'Designed to allow the student to develop a higher level of technical proficiency, with an emphasis on the application and analysis of various movement principles as they relate to dance and performance.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 221', 'APPROACHES TO DANCE-MAKING I', '5732', 'Class Status', 'W Wednesday 10:00 AM–12:45 PM', 'GR 128', 'Elizabeth Shea', 10, NULL, 'Lecture', '2', 'GRESHAM DINING HALL', ARRAY[]::TEXT[], 'An introduction to the craft of choreography. Students explore basic rhythmic, spatial, and dynamic materials through group improvisation and individual studies.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 231', 'INTRODUCTION TO DANCE STUDIES', '8513', 'Closed', NULL, 'WB WEB', 'Utam Moses', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introduction to Dance Studies establishes literacy in dance as an art-form. Using a global perspective, students will explore the elements of dance and how they manifest in culture from social settings to the concert stage. The roles of dancer, choreographer and spectator will be studied in multiple contexts of the discipline of theatrical, social and cultural dancing.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('THTR-D 254', 'INTERMEDIATE TAP DANCE', '15065', 'Class Status', 'MW Monday, Wednesday 3:15 PM–4:30 PM', 'TH A200', 'DJ Gray', 6, NULL, 'Activity', '1', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Second-level course in the technique and styles of tap dance and the use of tap dance steps to create original choreography. Development of tap dance as a musical and visual art form.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 302', 'A SOMATIC APPROACH TO CONTEMPORARY BALLET PRACTICES', '4717', 'Class Status', 'MTuThF Monday, Tuesday, Thursday, Friday 9:25 AM–10:55 AM', 'GR 128', 'Christian Claessens', 18, NULL, 'Lecture', '3', 'GRESHAM DINING HALL', ARRAY[]::TEXT[], 'Focuses on anatomically based ballet technique, with respect for individual physical differences. Emphasizes classical ballet vocabulary, along with sound alignment, deep muscular core support, and efficient movement mechanics. Explores contemporary trends in ballet performance and choreography.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 311', 'DANCE PRACTICES V', '5966', 'Closed', 'MTuThF Monday, Tuesday, Thursday, Friday 11:15 AM–12:45 PM', 'GR 128', 'Beatrice Capote, Utam Moses, kate lyons', 0, NULL, 'Lecture', '3', 'GRESHAM DINING HALL', ARRAY[]::TEXT[], 'Designed as an intensive immersion in both theory and practice of dance technique. Through readings, discussions, writings, and experiential learning, students gain an intimate understanding of both the artistic and physiological principles that guide performance in modern dance.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 355', 'ADVANCED MODERN DANCE', '5838', 'Closed', 'TuTh Tuesday, Thursday 1:15 PM–2:30 PM', 'GR 127', 'kate lyons', 0, NULL, 'Activity', '2', 'GRESHAM DINING HALL', ARRAY[]::TEXT[], 'Advanced techniques in modern dance with emphasis on performance of movement patterns and individual creative work.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 361', 'INDIANA UNIVERSITY CONTEMPORARY DANCE THEATRE', '3430', 'Class Status', 'MW Monday, Wednesday 6:25 PM–8:25 PM', 'TH A217', 'Stafford Berry', 21, NULL, 'Lecture', '1', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'A modern dance repertory company.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 361', 'INDIANA UNIVERSITY CONTEMPORARY DANCE THEATRE', '6309', 'Class Status', 'MW Monday, Wednesday 4:05 PM–6:05 PM', 'GR 127', 'Selene Carter', 12, NULL, 'Lecture', '1', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'A modern dance repertory company.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 361', 'INDIANA UNIVERSITY CONTEMPORARY DANCE THEATRE', '9541', 'Class Status', 'MW Monday, Wednesday 4:05 PM–6:05 PM', 'GR 128', 'Beatrice Capote', 15, NULL, 'Lecture', '1', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'A modern dance repertory company.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 361', 'INDIANA UNIVERSITY CONTEMPORARY DANCE THEATRE', '9542', 'Class Status', 'TuTh Tuesday, Thursday 2:40 PM–4:40 PM', 'GR 127', 'Robert Burden', 13, NULL, 'Lecture', '1', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'A modern dance repertory company.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 361', 'INDIANA UNIVERSITY CONTEMPORARY DANCE THEATRE', '9543', 'Class Status', 'TuTh Tuesday, Thursday 5:00 PM–7:00 PM', 'GR 128', 'Elizabeth Shea, Alexis Beverly', 13, NULL, 'Lecture', '1', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'A modern dance repertory company.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 361', 'INDIANA UNIVERSITY CONTEMPORARY DANCE THEATRE', '9804', 'Class Status', NULL, NULL, 'Elizabeth Shea, Selene Carter, Alexis Beverly', 6, NULL, 'Lecture', '1', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'A modern dance repertory company.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 411', 'DANCE PRACTICES VII', '5504', 'Closed', 'MTuThF Monday, Tuesday, Thursday, Friday 11:15 AM–12:45 PM', 'GR 128', 'Beatrice Capote, Utam Moses, kate lyons', 0, NULL, 'Lecture', '3', 'GRESHAM DINING HALL', ARRAY[]::TEXT[], 'Instructor-guided practicum in current issues regarding contemporary dance technique and trends in performance. Provides a practical culminating experience for senior dance majors as they prepare to enter the professional world.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 421', 'CHOREOGRAPHIC PERFORMANCE PROJECT', '7013', 'Class Status', 'MW Monday, Wednesday 1:15 PM–2:30 PM', 'GR 127', 'Selene Carter', 6, NULL, 'Lecture', '2', 'GRESHAM DINING HALL', ARRAY[]::TEXT[], 'Under faculty guidance, each student is responsible for initiating and developing a completed work for concert performance.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 456', 'ADVANCED JAZZ DANCE', '1978', 'Class Status', 'TuTh Tuesday, Thursday 1:05 PM–2:20 PM', 'GR 128', 'Robert Burden', 17, NULL, 'Activity', '2', 'GRESHAM DINING HALL', ARRAY[]::TEXT[], 'A continuation of instruction in the modern jazz style of movement with special emphasis on movement precision, clarity, and performance style. Students should be able to demonstrate an understanding of alignment and a mastery of advanced jazz-level combinations, demonstrate advanced and improved movement memory, demonstrate advanced and improved clarity, precision, and musicality, and show stylistic differences through the performance of movement combinations.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 461', 'METHODS OF MOVEMENT ANALYSIS', '5968', 'Class Status', 'MW Monday, Wednesday 2:55 PM–3:45 PM', 'GR 127', 'Selene Carter', 13, NULL, 'Lecture', '1', 'GRESHAM DINING HALL', ARRAY[]::TEXT[], 'Methods of analyzing movement in dance.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 462', 'SENIOR DANCE SUMMARY', '13261', 'Class Status', 'W Wednesday 11:15 AM–12:45 PM', 'GR 127', 'Beatrice Capote', 3, NULL, 'Lecture', '1', 'GRESHAM DINING HALL', ARRAY[]::TEXT[], 'Explores current issues and trends in dance performance and education through discussion and practicum.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('THTR-D 483', 'TOPICS IN DANCE', '11085', 'Class Status', 'TuTh Tuesday, Thursday 2:40 PM–4:40 PM', 'GR 127', 'Robert Burden', 13, NULL, 'Studio', '1', 'GRESHAM DINING HALL', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental dance courses.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 483', 'TOPICS IN DANCE', '34046', 'Class Status', NULL, 'HD TBA', 'Elizabeth Shea', 3, NULL, 'Studio', '1', 'GRESHAM DINING HALL', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental dance courses.', ARRAY[]::TEXT[], NULL),
    ('THTR-D 484', 'PROFESSIONAL BODY WORK CERTIFICATION', '29403', 'Class Status', 'TuTh Tuesday, Thursday 8:30 AM–10:30 AM', 'GR 127', 'Erin Thomas', 5, NULL, 'Lecture', '3', 'GRESHAM DINING HALL', ARRAY[]::TEXT[], 'Provides students the opportunity to gain knowledge in the arena of somatic body work as well as pursue professional certifications in specific areas. Certifications in yoga, as granted through the Yoga Alliance, and Stott Pilates will be offered in alternating years.', ARRAY[]::TEXT[], NULL),
    ('THTR-G 599', 'THESIS RESEARCH', '3402', 'Class Status', NULL, NULL, 'Jennifer Goodlander', 5, NULL, 'Research', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
    ('THTR-G 901', 'ADVANCED RESEARCH', '3041', 'Class Status', NULL, NULL, 'Jennifer Goodlander', 10, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 100', 'INTRODUCTION TO THEATRE', '3042', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'TH A201', 'Jennifer Lale', 0, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Exploration of theatre as collaborative art. Investigation of the dynamics and creativity of theatre production through plays, theatrical space, and cultural context, with particular attention to the roles and interaction of the audience, playwrights, directors, actors, designers, producers, and critics.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('THTR-T 100', 'INTRODUCTION TO THEATRE', '4495', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'TH A201', 'Jennifer Lale', 0, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Exploration of theatre as collaborative art. Investigation of the dynamics and creativity of theatre production through plays, theatrical space, and cultural context, with particular attention to the roles and interaction of the audience, playwrights, directors, actors, designers, producers, and critics.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('THTR-T 101', 'SCRIPT ANALYSIS FOR THE THEATRE', '29469', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'AD A152', 'Megan Lederman', 2, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Close analysis and study of both traditional and non-traditional play texts in terms of structure, genre, style, character, themes, language, dramatic action and dramatic event. Plays are examined from the point-of-view of the actor, director, designer, producer, critic, scholar, and audience.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('THTR-T 101', 'SCRIPT ANALYSIS FOR THE THEATRE', '4496', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'AD A152', 'Sheridan Schreyer', 0, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Close analysis and study of both traditional and non-traditional play texts in terms of structure, genre, style, character, themes, language, dramatic action and dramatic event. Plays are examined from the point-of-view of the actor, director, designer, producer, critic, scholar, and audience.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('THTR-T 108', 'GREAT PERFORMANCES IN FILM', '9760', 'Closed', 'TuTh Tuesday, Thursday 4:50 PM–6:20 PM', 'WB WEB', 'Jonathan Michaelsen', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'In-depth examination of a single actor''s performances in films spanning the course of his/her career. Includes methods of character creation as well as the history and theory of acting and performance.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('THTR-T 117', 'BEGINNING MUSICAL THEATRE DANCE', '34808', 'Class Status', 'TuTh Tuesday, Thursday 3:00 PM–4:30 PM', 'TH A200', 'Sherilyn Foley', 7, NULL, 'Activity', '1', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Focuses on the foundations of dance, beginning with strength building exercises, stylized movement across the floor, and dance combinations that will further the understanding of the myriad of styles within the Musical Theatre Dance canon.', ARRAY[]::TEXT[], NULL),
