IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('THTR-T 121', 'ACTING I FOR MAJORS: INTRODUCTION TO ACTING', '11487', 'Class Status', 'MW Monday, Wednesday 10:50 AM–12:35 PM', 'AD A052', 'Gretchen Hall', 3, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'An accelerated level course. Supplementary theories and methodology to expand the introduction to sensory awareness, physical and vocal exercises, improvisation and scene study.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('THTR-T 121', 'ACTING I FOR MAJORS: INTRODUCTION TO ACTING', '3252', 'Closed', 'TuTh Tuesday, Thursday 9:00 AM–10:45 AM', 'AD A280', 'Jenny McKnight', 0, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'An accelerated level course. Supplementary theories and methodology to expand the introduction to sensory awareness, physical and vocal exercises, improvisation and scene study.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('THTR-T 125', 'PERFORMANCE AS ART AND DESIGN', '3710', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'TH A201', 'Linda Pisano, Reuben Lucas', 0, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Introduces the process of design as it relates to the performing arts and entertainment. Explores methods of collaboration, design thinking, concepts of style, and perceptions of both individual and socio-historical aesthetic as it relates to storytelling for an audience.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('THTR-T 130', 'STAGE MAKE-UP DESIGN', '13267', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'TH A206', 'Katie Sickmeier', 1, NULL, 'Lecture', '1', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Introduction to basic theories and skills in stage makeup. Survey covers corrective, period, basic prosthetics, and other effects used in performance.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 168', 'THEATRE PRACTICUM', '33756', 'Class Status', NULL, 'HD TBA', 'Linda Pisano, Jeff Baldwin, Heather Milam, Allen Hahn', 7, NULL, 'Practicum', '1–3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'The study and application of theatre practices. Students will be assigned to all levels of departmental production for applied practice.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 203', 'IU BROADWAY CABARET', '5055', 'Class Status', 'M Monday 4:45 PM–6:15 PM', 'AD A280', 'Raymond Sage, Susan Swaney, Brandon Magid', 4, NULL, 'Lecture', '0–1', 'AUDITORIUM', ARRAY[]::TEXT[], 'Touring performance ensemble dedicated to the American Songbook and musical theatre literature. May be repeated for a maximum of 4 credit hours.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 204', 'THEATRE DANCE', '29672', 'Class Status', 'TuTh Tuesday, Thursday 2:50 PM–4:20 PM', 'AD A350', 'DJ Gray', 3, NULL, 'Activity', '2', 'AUDITORIUM', ARRAY[]::TEXT[], 'Develops dance techniques required for a musical theater career. Warm-up techniques of Katherine Dunham and Jack Cole combined with classical ballet technique. Exercises to develop stamina, line, isolation, extension, turns, jumps, and hinges at and away from the barre. Focus on discovering ability to embody emotion and character in movement.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 220', 'ACTING II: SCENE STUDY', '3045', 'Closed', 'TuTh Tuesday, Thursday 12:55 PM–2:40 PM', 'AD A280', 'Jonathan Michaelsen', 0, NULL, 'Practice', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Techniques for expressing physical, intellectual, and emotional objectives. Study, creation, and performance from varied dramas.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 254', 'INTRODUCTION TO PLAYWRITING', '10071', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'AD A151', 'Julia Cerqueira', 7, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Introduction to the creative process and the fundamentals of playwriting, including structure, character creation, dialogue, conflict, dramatic action, and setting. Requires in-class exercises and the writing of several short plays.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('THTR-T 301', 'MUSICAL THEATRE DANCE STYLES I', '14089', 'Class Status', 'MW Monday, Wednesday 9:00 AM–10:30 AM', 'AD A350', 'Jamie Cage', 5, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Dance styles of the 1920''s through the 1950''s are explored and performed, including the works of choreographers Fred Astaire, Hermes Pan, Agnes de Mille, Jerome Robbins and Gower Champion.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 305', 'VOICE FOR MUSICAL THEATRE', '3711', 'Class Status', 'W Wednesday 4:45 PM–6:15 PM', 'AD A280', 'Raymond Sage', 2, NULL, 'Lecture', '1', 'AUDITORIUM', ARRAY[]::TEXT[], 'Private study of vocal performance focusing on the development of the vocal instrument for musical theatre repertoire.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 305', 'VOICE FOR MUSICAL THEATRE', '4379', 'Class Status', 'W Wednesday 4:45 PM–6:15 PM', 'AD A280', 'Scott Hogsed', 2, NULL, 'Lecture', '1', 'AUDITORIUM', ARRAY[]::TEXT[], 'Private study of vocal performance focusing on the development of the vocal instrument for musical theatre repertoire.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 305', 'VOICE FOR MUSICAL THEATRE', '33886', 'Class Status', 'W Wednesday 4:45 PM–6:15 PM', 'AD A280', 'Raymond Sage', 3, NULL, 'Lecture', '1', 'AUDITORIUM', ARRAY[]::TEXT[], 'Private study of vocal performance focusing on the development of the vocal instrument for musical theatre repertoire.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 305', 'VOICE FOR MUSICAL THEATRE', '5056', 'Closed', 'W Wednesday 4:45 PM–6:15 PM', 'AD A280', 'Susan Swaney', 0, NULL, 'Lecture', '1', 'AUDITORIUM', ARRAY[]::TEXT[], 'Private study of vocal performance focusing on the development of the vocal instrument for musical theatre repertoire.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 306', 'MUSICAL THEATRE WORKSHOP FOR NON-BFA STUDENTS', '30040', 'Class Status', 'TuTh Tuesday, Thursday 4:45 PM–6:15 PM', 'AD A052', 'Ryan Andrews', 1, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'The workshop explores performance techniques for musical theatre focusing on synthesizing acting, singing, and dancing into dramatic action and character revelation. Not open to B.F.A. Musical Theatre majors.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 319', 'ACTING III: ADVANCED SCENE STUDY', '11911', 'Closed', 'MW Monday, Wednesday 3:00 PM–4:45 PM', 'TH A207', 'Jenny McKnight', 0, NULL, 'Practice', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Emphasizes ensemble acting, study and performance of early modern Realism, and contemporary American texts.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 325', 'VOICE AND SPEECH', '3047', 'Closed', 'TuTh Tuesday, Thursday 12:55 PM–2:40 PM', 'AD A052', 'Gretchen Hall', 0, NULL, 'Practice', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Introduction to voice production. Emphasizes relaxation, breathing, and the production of vocal sounds: deals with vocal habits and cultural holds through exercises and vocal workouts. Introduction to phonetics and practical work with text while freeing the voice and redeveloping a passion for language.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 334', 'COSTUME CONSTRUCTION I', '5983', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:45 PM', 'TH A203', 'Beth Wallace', 0, NULL, 'Lecture', '2', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Introductory to intermediate costume construction techniques, theatrical wardrobe crew basics, and information on fabric and materials used in theatrical costumes.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 335', 'STAGE LIGHTING DESIGN', '3048', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'TH A009', 'Allen Hahn', 0, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Introduction to the process of determining and implementing a lighting design. Analytical skills, concept development, design methods, lighting technology, and practical applications are covered.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 340', 'DIRECTING I: FUNDAMENTALS OF DIRECTING', '3049', 'Class Status', 'MW Monday, Wednesday 10:50 AM–12:35 PM', 'TH A207', 'Grant Goodman', 4, NULL, 'Practice', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Introduction to theories, process and skills (text analysis, working with actors, staging, and telling a story), culminating in a final project.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 340', 'DIRECTING I: FUNDAMENTALS OF DIRECTING', '13287', 'Class Status', 'TuTh Tuesday, Thursday 10:50 AM–12:35 PM', 'TH A207', 'Jennifer Goodlander', 8, NULL, 'Practice', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Introduction to theories, process and skills (text analysis, working with actors, staging, and telling a story), culminating in a final project.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 347', 'INTRODUCTION TO SOUND DESIGN FOR THE THEATRE', '3451', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'TH A002', 'Andrew Hopson', 3, NULL, 'Lecture', '2', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Within the framework of theatrical environments, this course introduces the student to acoustic principles, audio equipment used in theatrical productions, psycho-acoustical considerations, understanding sound signals and how to manipulate them, computer sound mixing systems, and sound design principles.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 350', 'ENTERTAINMENT TECHNOLOGY AND PRODUCTION', '7501', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'AD A151', 'Jeff Baldwin', 0, NULL, 'Lecture', '2', 'AUDITORIUM', ARRAY[]::TEXT[], 'Modern technologies are used to enhance or make possible the entertainment experience. The theatrical design process and engineering coalesce in the development, design, and implementation of solutions for live production including theatre, dance, opera, ballet, musicals, exhibits and performance art.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 351', 'MUSICAL THEATRE STUDIO I: ACTING THE SONG', '13278', 'Class Status', 'MW Monday, Wednesday 10:50 AM–12:35 PM', 'TH A200', 'Richard Roland', 1, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Focuses on the objective of the character singing the song by identifying the needs, obstacles, tactics, expectations, and given circumstances of the song. Particular attention is paid to deep analysis of the text of the song before it is performed.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 353', 'MUSICAL THEATRE STUDIO III: AUDITION TECHNIQUE', '13279', 'Closed', 'TuTh Tuesday, Thursday 10:50 AM–12:35 PM', 'TH A200', 'Richard Roland', 0, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Focuses on audition technique, including building of an audition repertoire, creating and maintaining a clear and concise résumé, establishing a system of analysis of audition and callback materials, mock-callbacks with guest casting and music directors. Integrates business practices and artistic choices unique to the MT performer.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 359', 'THEATRE PRODUCTION STUDIO', '4352', 'Class Status', NULL, NULL, 'Andrew Hopson, Reuben Lucas, Heather Milam, Allen Hahn, Jeff Baldwin, Katie Sickmeier, Linda Pisano', 10, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Intermediate, hands-on production course that teaches the theatre production process within a specific focus. Students gain proficiency within a specific theatre production are and are engaged in a managerial role in an academic production, including the development of production documentation. Student gain skills in communication, organization, and coordination.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 370', 'HISTORY OF THEATRE AND DRAMA I', '5253', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'TH A201', 'Eric Mayer-Garcia', 31, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'World-wide development of theatre and drama from beginnings to present. Study of theatre arts and culture institutions; focus on historical context for plays and performances; emphasis on research methods in theatre history. Beginnings to circa 1700.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('THTR-T 399', 'READING, RESEARCH, PERFORMANCE FOR HONORS', '3050', 'Class Status', NULL, NULL, 'Jennifer Lale', 7, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('THTR-T 401', 'MUSICAL THEATRE SENIOR SHOWCASE', '4298', 'Class Status', 'MW Monday, Wednesday 1:00 PM–2:15 PM', 'AD A280', 'DJ Gray, Richard Roland, Brandon Magid', 4, NULL, 'Lecture', '1', 'AUDITORIUM', ARRAY[]::TEXT[], 'Introduction to business and marketing techniques for success in professional theatre. Specific instruction in the audition process culminating in performance for agents and casting directors.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 403', 'SENIOR MUSICAL THEATRE DANCE AUDITION', '10469', 'Class Status', 'TuTh Tuesday, Thursday 11:15 AM–12:45 PM', 'AD A350', 'DJ Gray', 4, NULL, 'Lecture', '2–3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Focuses on the art of the dance audition in the professional world of musical theatre. Maintains and improves dance skills through daily jazz/ballet warmups and quick study dance combinations in various styles. Includes research on current Broadway choreographers, ongoing practice in professional audition techniques, and live musicians.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 410', 'MOVEMENT FOR THE THEATRE I', '5252', 'Class Status', 'MW Monday, Wednesday 10:50 AM–12:35 PM', 'AD A350', 'Bobby Perez', 2, NULL, 'Practice', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Introduction to fundamental principles and methodologies of movement training for the actor. Emphasis on connecting to imagery and impulse, conditioning, centering and alignment, physical characterization, and kinesthetic awareness in relation to the self, other actors, and the space.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 425', 'INTRODUCTION TO THEATRICAL DRAFTING', '10088', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'TH A002', 'Jeff Baldwin', 3, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'A studio course consisting of both traditional hand drafting techniques and digital CAD techniques as they are used in theatrical production communication.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 430', 'COSTUME TECHNOLOGY II', '9401', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'TH A203', 'Heather Milam', 6, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Further development of construction techniques for interested students who have satisfactorily completed T230. Provides a foundation of sewing, craft, fitting, and patternmaking techniques for use in developing a construction project and performing production assignments.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 437', 'SCENE PAINTING I', '29418', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'TH A103', 'Michelle Moore', 0, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'A studio course introducing techniques and equipment of theatrical scenic painting.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 438', 'ADVANCED STAGE LIGHTING DESIGN', '11350', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'TH A009', 'Allen Hahn', 4, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Stage lighting design-concept development, presentation, and implementation are emphasized, along with advanced lighting techniques and approaches. A practicum will be assigned.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 447', 'AESTHETICS OF SOUND DESIGN', '7670', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'TH A002', 'Andrew Hopson', 6, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Focuses on concept development and implementation. Students are exposed to various design challenges and processes for sound design in a range of production styles and approaches.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 462', 'DEVELOPMENT OF DRAMATIC ART 3', '11176', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'AD A152', 'Jennifer Lale', 0, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Dramatic art in Western world from beginnings to present. Emphasis on drama in theatre of its origin and on methods of interpreting plays of the past in contemporary theatre. III. 1940 to present.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('THTR-T 468', 'ASIAN PERFORMANCE', '29508', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'TH A207', 'Jennifer Goodlander', 0, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'An in-depth study of the major forms and styles of traditional and contemporary theatre, dance, and puppet performances from around Asia (broadly defined).', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('THTR-T 483', 'TOPICS IN THEATRE AND DRAMA', '29654', 'Class Status', 'TuTh Tuesday, Thursday 4:45 PM–6:15 PM', 'AD A280', 'Ansley Valentine', 3, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental courses.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 491', 'WORKING IN THE PROFESSION', '8569', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'TH A201', 'Ansley Valentine', 10, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Preparation for a professional theatre career. Topics include auditions, managers, unions, finances, regional theatre, professional courtesy, and realities of the work environment.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('THTR-T 499', 'READING, RESEARCH, PERFORMANCE FOR HONORS', '3051', 'Class Status', NULL, NULL, 'Jennifer Lale', 5, NULL, 'Readings', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('THTR-T 500', 'INTRODUCTION TO GRADUATE STUDY', '3052', 'Class Status', 'F Friday 9:00 AM–10:45 AM', 'AD A262', 'Sarah Johnson', 2, NULL, 'Lecture', '1.5', 'AUDITORIUM', ARRAY[]::TEXT[], 'Methods and materials of theatre research, principles of scholarly investigation, and strategies of production research.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 518', 'SCENIC PAINTING FOR THE STAGE', '29419', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'TH A103', 'Michelle Moore', 0, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'An introduction theatrical painting course specializing in the area of scenic textures and faux finishes. It will expose the student to the many different ways to texture, paint and finish scenery for the stage.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 528', 'STUDIES IN STAGE SCENERY', '7984', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'TH A205', 'Reuben Lucas', 7, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Selected problems in designing stage scenery; composition and style.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 528', 'STUDIES IN STAGE SCENERY', '29436', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'TH A205', 'Reuben Lucas', 7, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Selected problems in designing stage scenery; composition and style.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 529', 'STUDIES IN THEATRE TECHNOLOGY', '12085', 'Class Status', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'TH A002', 'Jeff Baldwin', 5, NULL, 'Lecture', '1', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Selected problems in scenery engineering, stage machinery, problem-solving, technical management, estimation and planning, and design and execution of advanced projects.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 529', 'STUDIES IN THEATRE TECHNOLOGY', '12086', 'Class Status', NULL, 'HD TBA', 'Jeff Baldwin', 8, NULL, 'Lecture', '1', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Selected problems in scenery engineering, stage machinery, problem-solving, technical management, estimation and planning, and design and execution of advanced projects.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 529', 'STUDIES IN THEATRE TECHNOLOGY', '29468', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'TH A002', 'Jeff Baldwin', 7, NULL, 'Lecture', '1', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Selected problems in scenery engineering, stage machinery, problem-solving, technical management, estimation and planning, and design and execution of advanced projects.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 530', 'ADVANCED COSTUME DESIGN AESTHETICS', '29437', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'TH A205', 'Katie Sickmeier', 7, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Intensive study of costume design and application of design principles. Students will produce projects in various genres. Theatre, opera, ballet and musical theatre are just some of the forms surveyed. Students work in a collaborative design arena that emulates the process for whichever genre they are designing in.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 531', 'COSTUME TECHNOLOGY II', '9402', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'TH A203', 'Heather Milam', 6, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Provides a strong base in costume construction techniques for incoming graduate students. It provides a foundation of sewing, craft, fitting, and patternmaking techniques as well as training in team management from which the students may develop a construction project and perform assignments including supervisory roles in production work.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 539', 'FUNDAMENTALS OF THEATRICAL DRAFTING', '10089', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'TH A002', 'Jeff Baldwin', 3, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'A studio course consisting of both traditional hand drafting techniques and digital CAD techniques as they are used in theatrical production communication.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 546', 'STAGE LIGHTING DESIGN', '11351', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'TH A009', 'Allen Hahn', 4, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Stage lighting design concept development, presentation, and implementation are emphasized. Advanced lighting techniques and approaches. A practicum will be assigned.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 547', 'SOUND DESIGN I', '8368', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'TH A002', 'Andrew Hopson', 6, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Study of the practical use, aesthetics, and implementation of sound in theatre productions. Focus is on using computers to assist in the creation, selection, and playback of sound cues. Topics include sound system operation and design for both plays and musicals. Emphasis on researching, selecting, and recording music for production.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 558', 'TOPICS IN DRAMATIC WRITING', '35352', 'Closed', 'M Monday 1:00 PM–4:00 PM', 'WB WEB', 'Sarah Grochala', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Primarily for students of the M.F.A. playwriting program. In-depth study of special topics in dramatic writing, literature, and/or theory.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 574', 'DRAMATURGY SEMINAR', '10017', 'Closed', 'W Wednesday 1:00 PM–4:00 PM', 'TH A300', 'Sarah Johnson', 0, NULL, 'Seminar', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Examines the history of dramaturgy and its relation to dramatic criticism and theory. Offers strategies for sparking dramaturgical dialogue across disciplines and best practices for the creation of dramaturgical casebooks and contextualizing material for audiences.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 583', 'TOPICS IN THEATRE AND DRAMA', '29655', 'Class Status', 'TuTh Tuesday, Thursday 4:45 PM–6:15 PM', 'AD A280', 'Ansley Valentine', 3, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental courses.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 583', 'TOPICS IN THEATRE AND DRAMA', '32166', 'Class Status', 'MW Monday, Wednesday 1:00 PM–2:45 PM', 'TH A200', 'Jenny McKnight, Grant Goodman', 4, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental courses.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 583', 'TOPICS IN THEATRE AND DRAMA', '29509', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'TH A207', 'Jennifer Goodlander', 0, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental courses.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 583', 'TOPICS IN THEATRE AND DRAMA', '29665', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'TH A300', 'Russell Valentino', 0, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental courses.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 583', 'TOPICS IN THEATRE AND DRAMA', '34140', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'AD A262', 'Eric Mayer-Garcia', 0, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental courses.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 600', 'DIRECTED RESEARCH', '3053', 'Class Status', NULL, NULL, 'Jennifer Goodlander', 8, NULL, 'Research', '1–6', NULL, ARRAY[]::TEXT[], 'Individual supervised research projects.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 604', 'PORTFOLIO SEMINAR FOR COSTUME DESIGNERS', '6352', 'Closed', NULL, 'HD TBA', 'Katie Sickmeier', 0, NULL, 'Lecture', '1', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Prepares students to consider, evaluate, and state academic and professional goals, as well as learning how to develop portfolio content and outlines, preparing both digital and hard copy portfolios along with resumes for summer employment and internships. To be taken in all three years of the MFA costume design degree.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 626', 'ADVANCED SCENIC DESIGN II', '13273', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'TH A205', 'Reuben Lucas', 8, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'An MFA capstone studio course in the theory, process, and techniques of scenic design for the theatre. Design projects include non-theatrical venues and diverse areas of the entertainment industry. Portfolio quality presentation is expected.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 630', 'MILLINERY', '29454', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'TH A203', 'Katie Sickmeier', 6, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'A foundation in the techniques and design of millinery and headwear as an important part of developing character and establishing time, culture, and social class. The course will cover several major materials and problems faced by the professional milliner in the performing arts.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 646', 'LIGHTING DESIGN SEMINAR', '8119', 'Class Status', 'W Wednesday 9:00 AM–11:00 AM', 'TH A009', 'Allen Hahn', 3, NULL, 'Seminar', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Development of a lighting designer''s critical experience with color, timing, volumetric space, lateral thinking, and creativity are addressed in successive semesters in this project-based course, heavy on critique. With these supporting skills, the designer''s work in production can be conducted with greater confidence and assurance of a successful outcome.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 650', 'LIGHTING DESIGN IN PRODUCTION', '10097', 'Class Status', 'M Monday 10:00 AM–11:00 AM', 'TH A009', 'Allen Hahn', 5, NULL, 'Practicum', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Lighting designers can only practice their craft by building and executing it in time and space. This course gives them the opportunity to be evaluated for that work through a dialogue-based faculty-guided process from conceptualization, through development and technical rehearsals to opening night.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 675', 'DRAMATIC THEORY', '29510', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'AD A262', 'Eric Mayer-Garcia', 3, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'An historical overview of the ways seminal thinkers - from ancient theorists to contemporary critics -- have tried to determine what theatre is, how it works, and what it should contribute to the world. Examination of how these theories inform contemporary theatre practice.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 700', 'INDEPENDENT STUDY', '3054', 'Class Status', NULL, NULL, 'Linda Pisano', 16, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('THTR-T 701', 'READINGS IN THEATRE HISTORY AND DRAMA', '3055', 'Class Status', NULL, NULL, 'Jennifer Goodlander', 15, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'Supervised readings in theatre history, dramatic literature, theory and criticism.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 720', 'INTERNSHIP IN ACTING', '29585', 'Class Status', NULL, NULL, 'Jenny McKnight', 16, NULL, 'Lecture', '3–9', NULL, ARRAY[]::TEXT[], 'Internship in a professional theatre for one semester or equivalent period of time.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 722', 'GRADUATE PERFORMANCE PRACTICUM', '14836', 'Class Status', NULL, 'HD TBA', 'Jenny McKnight', 5, NULL, 'Practicum', '1–2', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Acting and Directing MFA students are required to enroll in Graduate Performance Practicum in alignment with production assignments that are undertaken in fulfillment of the curricular requirements of the degree. If a student is registered for credit on the production in another course, registration for THTR-T 722 is not required.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 723', 'GRADUATE ACTING FOR THE CAMERA', '29587', 'Class Status', 'MW Monday, Wednesday 3:30 PM–5:30 PM', 'AD A060', 'Ansley Valentine', 8, NULL, 'Lecture', '2', 'AUDITORIUM', ARRAY[]::TEXT[], 'This eight week intensive exploration of the fundamentals of acting for the camera is designed to develop students'' on-camera acting skills.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 725', 'THIRD YEAR VOICE FOR THE MFA I', '29588', 'Class Status', 'TuTh Tuesday, Thursday 3:00 PM–4:45 PM', 'TH A207', 'Gretchen Hall', 8, NULL, 'Lecture', '3', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'Establishing a strong vocal process and foundation for the graduate student to take into professional acting work. An understanding of the fundamentals of voice techniques, including breath, connection and use of emotional release giving the student strong process for text analysis by looking at poetic as well as contemporary texts.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 895', 'M.A. THESIS', '3056', 'Class Status', NULL, NULL, 'Jennifer Goodlander', 10, NULL, 'Research', '1–5', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('THTR-T 897', 'M.F.A. THESIS', '3057', 'Class Status', NULL, NULL, 'Jennifer Goodlander', 1, NULL, 'Research', '1–10', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('THTR-T 899', 'PH D THESIS', '3058', 'Class Status', NULL, NULL, 'Jennifer Goodlander', 15, NULL, 'Research', '1–15', NULL, ARRAY[]::TEXT[], 'Dissertation research in specialized topics in Theatre and Drama.', ARRAY[]::TEXT[], NULL),
    ('THTR-T 899', 'PH D THESIS', '7618', 'Class Status', NULL, NULL, 'Jennifer Goodlander', 15, NULL, 'Research', '1–15', NULL, ARRAY[]::TEXT[], 'Dissertation research in specialized topics in Theatre and Drama.', ARRAY[]::TEXT[], NULL),
    ('THTR-X 476', 'PRACTICUM IN COMMUNITY DANCE PARTNERSHIPS', '5969', 'Class Status', NULL, NULL, 'Selene Carter', 20, NULL, 'Internship', '3', NULL, ARRAY[]::TEXT[], 'Dance majors will design, implement and teach a dance education program for community partners in local social service settings that promote well-being and dance appreciation through personal, and physical creative expression.', ARRAY[]::TEXT[], NULL),
    ('THTR-X 490', 'INDEPENDENT STUDY IN THEATRE AND DRAMA', '7203', 'Class Status', NULL, NULL, 'Linda Pisano', 10, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Readings, performances, experiments, and reports in area of student''s special interest.', ARRAY[]::TEXT[], NULL),
    ('VICT-V 611', 'VICTORIAN BRITAIN: CULTURE AND SOCIETY, 1820-1900', '30424', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 146', 'Lara Kriegel', 6, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('VSCI-G 901', 'ADVANCED RESEARCH', '3145', 'Class Status', NULL, NULL, 'Stephen Burns', 16, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('VSCI-V 250', 'THE PHYSICS, BIOLOGY, AND NEUROSCIENCE OF HUMAN VISION', '29873', 'Class Status', 'Th Thursday 4:45 PM–6:00 PM', 'OP 105', 'Nicholas Port', 11, 'Lecture', 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Examining vision, which draws from the scientific disciplines of physics, biology, neuroscience and psychology. Following the process beginnings deeply rooted in physics (optics) thru final stages of perception, which are not merely image processed versions of the optical input, but creations of our own brain, from "Photons to Fantasy".', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('VSCI-V 250', 'THE PHYSICS, BIOLOGY, AND NEUROSCIENCE OF HUMAN VISION', '29874', 'Class Status', 'Th Thursday 6:15 PM–7:45 PM', 'OP 102', 'Nicholas Port', 11, 'Laboratory', 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Examining vision, which draws from the scientific disciplines of physics, biology, neuroscience and psychology. Following the process beginnings deeply rooted in physics (optics) thru final stages of perception, which are not merely image processed versions of the optical input, but creations of our own brain, from "Photons to Fantasy".', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('VSCI-V 550', 'THE MIRACLE OF SIGHT', '15132', 'Class Status', 'Th Thursday 4:45 PM–6:00 PM', 'OP 105', 'Nicholas Port', 7, 'Lecture', 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'The process of vision includes physics, biology, neuroscience and psychology. This class will follow the process from its beginnings, which are deeply rooted in physics (optics) to the final stages of perception, which are not merely image processed versions of the optical input, but creations of our own brain.', ARRAY[]::TEXT[], NULL),
    ('VSCI-V 550', 'THE MIRACLE OF SIGHT', '15133', 'Class Status', 'Th Thursday 6:15 PM–7:45 PM', 'OP 102', 'Nicholas Port', 7, 'Laboratory', 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'The process of vision includes physics, biology, neuroscience and psychology. This class will follow the process from its beginnings, which are deeply rooted in physics (optics) to the final stages of perception, which are not merely image processed versions of the optical input, but creations of our own brain.', ARRAY[]::TEXT[], NULL),
    ('VSCI-V 595', 'FIRST-YEAR RESEARCH', '3138', 'Class Status', NULL, NULL, 'Stephen Burns', 18, NULL, 'Independent Study', '1–5', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('VSCI-V 695', 'SECOND-YEAR RESEARCH', '3139', 'Class Status', NULL, NULL, 'Stephen Burns', 13, NULL, 'Independent Study', '1–5', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('VSCI-V 707', 'RETINAL IMAGING', '6890', 'Class Status', NULL, NULL, 'Ann Elsner', 6, NULL, 'Lecture', '2–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('VSCI-V 717', 'VISUAL DEVELOPMENT IN INFANCY AND EARLY CHILDHOOD', '5587', 'Class Status', NULL, NULL, 'T. Rowan Candy', 10, NULL, 'Lecture', '2–3', NULL, ARRAY[]::TEXT[], 'This course will provide an introduction to structural development of the human visual system; to functional development of the human visual system; and an introduction to methodology used to study visual development', ARRAY[]::TEXT[], NULL),
    ('VSCI-V 765', 'VISION SCIENCE SEMINAR', '3140', 'Class Status', 'F Friday 12:00 PM–12:50 PM', 'OP 111 OP 111', 'Hyungsik Lim', 19, NULL, 'Seminar', '1', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
